// Created: 2026-04-23

/**
 * Unit tests for posttool/metrics-dispatcher (Issue #1489, M121).
 *
 * Validates:
 *   - All 3 inner handlers are called per invocation (webhook-forwarder,
 *     metrics-bridge, context-crossing-warn)
 *   - One handler throwing does NOT prevent the others from running
 *   - additionalContext from inner handlers bubbles up unchanged
 *   - Empty/silent result when no inner handler emits context
 *   - Dispatcher never throws — telemetry is best-effort
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';

// Hoist the spies so vi.mock factories (which themselves get hoisted above
// module-scope const declarations) can reference them.
const { webhookSpy, metricsSpy, contextSpy } = vi.hoisted(() => ({
  webhookSpy: vi.fn(),
  metricsSpy: vi.fn(),
  contextSpy: vi.fn(),
}));

vi.mock('../../lifecycle/webhook-forwarder.js', () => ({
  webhookForwarder: webhookSpy,
}));
vi.mock('../../posttool/metrics-bridge.js', () => ({
  metricsBridge: metricsSpy,
}));
vi.mock('../../posttool/context-crossing-warn.js', () => ({
  contextCrossingWarn: contextSpy,
}));

import { metricsDispatcher, DISPATCHER_HANDLERS } from '../../posttool/metrics-dispatcher.js';
import { createTestContext } from '../fixtures/test-context.js';
import type { HookInput, HookResult } from '../../types.js';

function silentOk(): HookResult {
  return { continue: true, suppressOutput: true };
}

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session',
    tool_input: { command: 'echo hello' },
    ...overrides,
  };
}

describe('metricsDispatcher', () => {
  let ctx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    ctx = createTestContext({ projectDir: '/test/project', sessionId: 'test-session' });
    // Default: all handlers return silent success
    webhookSpy.mockResolvedValue(silentOk());
    metricsSpy.mockResolvedValue(silentOk());
    contextSpy.mockResolvedValue(silentOk());
  });

  describe('fan-out', () => {
    it('invokes all three handlers exactly once per call', async () => {
      await metricsDispatcher(makeInput(), ctx);

      expect(webhookSpy).toHaveBeenCalledTimes(1);
      expect(metricsSpy).toHaveBeenCalledTimes(1);
      expect(contextSpy).toHaveBeenCalledTimes(1);
    });

    it('passes the same input + ctx to every handler', async () => {
      const input = makeInput({ tool_name: 'Write' });
      await metricsDispatcher(input, ctx);

      expect(webhookSpy).toHaveBeenCalledWith(input, ctx);
      expect(metricsSpy).toHaveBeenCalledWith(input, ctx);
      expect(contextSpy).toHaveBeenCalledWith(input, ctx);
    });

    it('exposes DISPATCHER_HANDLERS in registration order (for logging reproducibility)', () => {
      expect(DISPATCHER_HANDLERS.map(h => h.name)).toEqual([
        'webhookForwarder',
        'metricsBridge',
        'contextCrossingWarn',
      ]);
    });
  });

  describe('failure isolation', () => {
    it('continues calling other handlers when webhookForwarder throws', async () => {
      webhookSpy.mockRejectedValue(new Error('sink unreachable'));

      const result = await metricsDispatcher(makeInput(), ctx);

      expect(metricsSpy).toHaveBeenCalledTimes(1);
      expect(contextSpy).toHaveBeenCalledTimes(1);
      // Dispatcher itself never throws — returns a valid result
      expect(result.continue).toBe(true);
    });

    it('continues when metricsBridge throws', async () => {
      metricsSpy.mockRejectedValue(new Error('disk full'));

      const result = await metricsDispatcher(makeInput(), ctx);

      expect(webhookSpy).toHaveBeenCalledTimes(1);
      expect(contextSpy).toHaveBeenCalledTimes(1);
      expect(result.continue).toBe(true);
    });

    it('continues when contextCrossingWarn throws', async () => {
      contextSpy.mockRejectedValue(new Error('corrupt state file'));

      const result = await metricsDispatcher(makeInput(), ctx);

      expect(webhookSpy).toHaveBeenCalledTimes(1);
      expect(metricsSpy).toHaveBeenCalledTimes(1);
      expect(result.continue).toBe(true);
    });

    it('never throws even when ALL handlers fail', async () => {
      webhookSpy.mockRejectedValue(new Error('A'));
      metricsSpy.mockRejectedValue(new Error('B'));
      contextSpy.mockRejectedValue(new Error('C'));

      await expect(metricsDispatcher(makeInput(), ctx)).resolves.toBeDefined();
    });

    it('logs handler-level failure summary via ctx.log', async () => {
      webhookSpy.mockRejectedValue(new Error('A'));

      await metricsDispatcher(makeInput(), ctx);

      // Dispatcher logs: per-handler throw + summary line
      const warnCalls = (ctx.log as ReturnType<typeof vi.fn>).mock.calls.filter(
        c => c[2] === 'warn',
      );
      expect(warnCalls.length).toBeGreaterThanOrEqual(1);
    });
  });

  describe('additionalContext bubbling', () => {
    it('bubbles additionalContext from context-crossing-warn', async () => {
      contextSpy.mockResolvedValue({
        continue: true,
        suppressOutput: true,
        hookSpecificOutput: {
          hookEventName: 'PostToolUse',
          additionalContext: '[context] Session context crossed ~150,000 tokens.',
        },
      });

      const result = await metricsDispatcher(makeInput(), ctx);

      expect(result.hookSpecificOutput?.additionalContext).toContain(
        'crossed ~150,000 tokens',
      );
      expect(result.hookSpecificOutput?.hookEventName).toBe('PostToolUse');
    });

    it('concatenates additionalContext when multiple handlers emit', async () => {
      webhookSpy.mockResolvedValue({
        continue: true,
        suppressOutput: true,
        hookSpecificOutput: {
          hookEventName: 'PostToolUse',
          additionalContext: 'from webhook',
        },
      });
      contextSpy.mockResolvedValue({
        continue: true,
        suppressOutput: true,
        hookSpecificOutput: {
          hookEventName: 'PostToolUse',
          additionalContext: 'from context-crossing',
        },
      });

      const result = await metricsDispatcher(makeInput(), ctx);

      expect(result.hookSpecificOutput?.additionalContext).toContain('from webhook');
      expect(result.hookSpecificOutput?.additionalContext).toContain('from context-crossing');
    });

    it('returns silent success when no handler emits context', async () => {
      const result = await metricsDispatcher(makeInput(), ctx);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });

    it('ignores empty/whitespace-only additionalContext', async () => {
      webhookSpy.mockResolvedValue({
        continue: true,
        suppressOutput: true,
        hookSpecificOutput: {
          hookEventName: 'PostToolUse',
          additionalContext: '   \n  \n  ',
        },
      });

      const result = await metricsDispatcher(makeInput(), ctx);

      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });
  });
});
